using System;
using System.Collections.Specialized;
using System.Collections.ObjectModel;
using System.Text;
using NUnit.Framework;
using Tawala.XmlSupport;
using Tawala.RtfSupport;

namespace TawalaTest.RtfSupportTest
{
	[TestFixture]
	public class RtfImageTest
	{

		[Test]
		public void TenBy12RedFFGreen7DBlue3E()
		{
			string wmfFileString =
				"";

			RtfImage image = new RtfImage(wmfFileString);

			Assert.AreEqual(10, image.Width);
			Assert.AreEqual(12, image.Height);

			string expectedBase64PngString = 
				"iVBORw0KGgoAAAANSUhEUgAAAAoAAAAMCAIAAADUCbv3AAAAAXNSR0IArs4c6QAAAARnQU1BAACx\r\n" +
				"jwv8YQUAAAAgY0hSTQAAeiYAAICEAAD6AAAAgOgAAHUwAADqYAAAOpgAABdwnLpRPAAAABpJREFU\r\n" +
				"KFNj/F9ny4AHAKXxIIZRaWzhQyBYAFsXv6i+LNJ8AAAAAElFTkSuQmCC";

			Assert.AreEqual(expectedBase64PngString, image.Base64PngString);
		}

		[Test]
		public void GetBitmapInfoHeader()
		{
			string bmpInfoHeaderAndDataString =
				"";

			BitmapInfoHeader header = RtfImage.GetBitmapInfoHeader(bmpInfoHeaderAndDataString);

			Assert.AreEqual(40, header.headerSize);
			Assert.AreEqual(10, header.imageWidth);
			Assert.AreEqual(12, header.imageHeight);
			Assert.AreEqual(24, header.bitsPerPixel);

			const uint bytesPerPixel = 3;
			uint bytesPerRow = ((header.imageWidth * bytesPerPixel / 4) + 1) * 4;

			Assert.AreEqual(bytesPerRow * header.imageHeight, header.imageSize);
		}
	}
}
